async (page) => {
  // Walk east toward the beach (water visible to east in screenshots)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 1100, y: 400 });
  await page.waitForTimeout(4000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const items = parsed.nearby_entities.filter(e => e.type === 4);
  const mobs = parsed.nearby_entities.filter(e => e.type === 3).slice(0, 3);
  return JSON.stringify({
    pos: parsed.player_position,
    items: items.map(e => ({name: e.name, dist: e.distance})),
    mobs: mobs.map(e => ({name: e.name, dist: e.distance, click_x: e.click_x, click_y: e.click_y, on_screen: e.on_screen}))
  });
}

async (page) => {
