async (page) => {
  // Click the RESPAWN button
  await page.evaluate(() => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: 640, clientY: 364, bubbles: true }));
  });
  await page.waitForTimeout(3000);

  // Check if respawned
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s ? {pos: s.player_position, hp: s.player_stats.hp, logs: s.inventory?.filter(i => i.key === 'logs').length} : null;
  });
  console.log('After respawn: ' + JSON.stringify(state));

  // If still showing 0 hp or dead dialog, try warping
  if (!state || state.hp === 0) {
    // Try clicking respawn button via DOM
    await page.evaluate(() => {
      // Look for respawn button
      const buttons = document.querySelectorAll('button, .btn');
      buttons.forEach(b => {
        if (b.textContent.includes('RESPAWN') || b.textContent.includes('Respawn')) b.click();
      });
    });
    await page.waitForTimeout(3000);
  }

  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s ? {pos: s.player_position, hp: s.player_stats.hp, logs: s.inventory?.filter(i => i.key === 'logs').length, inv: s.inventory} : null;
  });
  return JSON.stringify(finalState);
}

