async (page) => {
  const countLogs = () => page.evaluate(() => {
    const inv = window.__latestGameState?.inventory || [];
    return inv.filter(i => i.key === 'logs').reduce((s, i) => s + (i.count || 1), 0);
  });

  const getState = () => page.evaluate(() => ({
    logs: (window.__latestGameState?.inventory || []).filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0),
    hp: window.game.player.hitPoints, maxHp: window.game.player.maxHitPoints,
    pos: { x: window.game.player.gridX, y: window.game.player.gridY },
    ljXP: window.game.player.skills[0]?.experience,
  }));

  const stepToward = async (tx, ty) => {
    await page.evaluate(({tx, ty}) => {
      const px = window.game.player.gridX, py = window.game.player.gridY;
      const dx = tx-px, dy = ty-py;
      const absDx = Math.abs(dx), absDy = Math.abs(dy);
      const xScale = absDx > 12 ? 12/absDx : 1;
      const yScale = absDy > 7 ? 7/absDy : 1;
      const scale = Math.min(xScale, yScale);
      const mx = px + Math.round(dx*scale), my = py + Math.round(dy*scale);
      const sx = 640+(mx-px)*48, sy = 360+(my-py)*48;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: sx, clientY: sy, bubbles: true}));
    }, {tx, ty});
    await page.waitForTimeout(5000);
  };

  let s = await getState();
  console.log('Start:', s);

  // Traverse dense oak forest areas in zig-zag pattern
  const waypoints = [
    [195, 120], [205, 112], [215, 118], [225, 113],  // N band
    [205, 125], [195, 130], [185, 125], [178, 120],  // middle band  
    [188, 130], [200, 135], [210, 128], [220, 135],  // lower band
  ];

  for (const [wx, wy] of waypoints) {
    s = await getState();
    if (s.hp < s.maxHp * 0.3) { await page.waitForTimeout(6000); }
    if (s.logs >= 12) break;

    await stepToward(wx, wy);
    s = await getState();
    console.log(`At (${s.pos.x},${s.pos.y}): logs=${s.logs} hp=${s.hp} ljXP=${s.ljXP}`);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return await getState();
}

