async (page) => {
  // Grind Rats for Strength XP - attack multiple Rats
  let kills = 0;

  for (let round = 0; round < 15; round++) {
    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const px = window.game.player.gridX, py = window.game.player.gridY;
      const hp = gs?.player_stats?.hp;
      const strength = window.game?.player?.skills?.[6];

      // Find nearest Rat on screen
      const rat = (gs?.nearby_entities||[]).find(e=>e.name==='Rat'&&e.type===3&&e.on_screen);
      if (!rat) return { no_rat: true, hp, strength: strength?.level, strXP: strength?.experience };

      // Click it
      const sx = 640+(rat.x-px)*48, sy = 360+(rat.y-py)*48;
      if (sx>=0&&sx<=1280&&sy>=0&&sy<=720) {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: sx, clientY: sy, bubbles: true}));
        return { attacked: true, rat: {x:rat.x,y:rat.y}, hp, strength: strength?.level, strXP: strength?.experience };
      }
      return { off_screen: true, hp, strength: strength?.level };
    });

    if (state.hp < 25) {
      // Find and eat Blueberry Bush
      await page.evaluate(() => {
        const bush = (window.__latestGameState?.nearby_entities||[]).find(e=>e.name==='Blueberry Bush');
        if (bush) {
          const px = window.game.player.gridX, py = window.game.player.gridY;
          const dx=bush.x-px, dy=bush.y-py;
          if (Math.abs(dx)<=12&&Math.abs(dy)<=7) {
            document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: 640+dx*48, clientY: 360+dy*48, bubbles: true}));
          }
        }
      });
      await page.waitForTimeout(3000);
      await page.evaluate(() => {
        const food = (window.__latestGameState?.inventory||[]).filter(i=>i.edible);
        if (food.length > 0) window.game.menu.getInventory().selectEdible(food[0].slot);
      });
    }

    await page.waitForTimeout(5000);
    if (state.strength >= 10) break;
  }

  const final = await page.evaluate(() => ({
    pos: window.__latestGameState?.player_position,
    hp: window.__latestGameState?.player_stats?.hp,
    strength_level: window.game?.player?.skills?.[6]?.level,
    strength_xp: window.game?.player?.skills?.[6]?.experience
  }));
  return JSON.stringify(final);
}

async (page) => {
  // Long grind loop for Strength XP - 40 rounds
  for (let round = 0; round < 40; round++) {
