async (page) => {
  // More efficient grind: find nearest mob and walk to it, then attack
  for (let round = 0; round < 30; round++) {
    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const px = window.game.player.gridX, py = window.game.player.gridY;
      const hp = gs?.player_stats?.hp;
      const strength = window.game?.player?.skills?.[6];

      // Find nearest Rat (prefer close ones)
      const mobs = (gs?.nearby_entities||[])
        .filter(e=>e.name==='Rat'&&e.type===3&&e.distance<=12)
        .sort((a,b)=>a.distance-b.distance);

      if (!mobs.length) return { no_mob: true, hp, strLevel: strength?.level, strXP: strength?.experience, pos:{x:px,y:py} };

      const mob = mobs[0];
      const dx = mob.x-px, dy = mob.y-py;
      // Use bounded step toward mob
      const xScale = Math.abs(dx)>12?12/Math.abs(dx):1;
      const yScale = Math.abs(dy)>7?7/Math.abs(dy):1;
      const scale = Math.min(xScale,yScale);
      const tx = px+Math.round(dx*scale), ty = py+Math.round(dy*scale);
      const sx = 640+(tx-px)*48, sy = 360+(ty-py)*48;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click',{clientX:sx,clientY:sy,bubbles:true}));
      return { attacked: mob.name, dist: mob.distance, hp, strLevel: strength?.level, strXP: strength?.experience, pos:{x:px,y:py} };
    });

    if (state.hp < 20 && !state.no_mob) {
      await page.evaluate(() => {
        const food = (window.__latestGameState?.inventory||[]).filter(i=>i.edible);
        if (food.length > 0) window.game.menu.getInventory().selectEdible(food[0].slot);
      });
    }

    await page.waitForTimeout(state.no_mob ? 2000 : 5000);

    const strLevel = await page.evaluate(() => window.game?.player?.skills?.[6]?.level);
    if (strLevel >= 10) return JSON.stringify({done: true, strLevel});
  }

  const final = await page.evaluate(() => ({
    pos: window.__latestGameState?.player_position,
    hp: window.__latestGameState?.player_stats?.hp,
    strength_level: window.game?.player?.skills?.[6]?.level,
    strength_xp: window.game?.player?.skills?.[6]?.experience
  }));
  return JSON.stringify(final);
}
